import { Board } from '../models/board.model';

export const inviteMember = async (req, res, next) => {
  try {
    const { memberId } = req.body;
    const boardId = req.params.id;
    const userId = req.user._id;

    const board = await Board.findById(boardId);
    if (!board) {
      return res.status(404).json({ message: 'Board not found' });
    }

    if (!board.owner.equals(userId)) {
      return res.status(403).json({ message: 'Only the board owner can invite members' });
    }

    if (board.members.includes(memberId)) {
      return res.status(400).json({ message: 'User is already a member' });
    }

    board.members.push(memberId);
    await board.save();

    res.status(200).json({ message: 'Member invited successfully' });
  } catch (error) {
    next(error);
  }
};

